const data = $input.first().json;
if (data.error || data.loggedOut) {
  throw new Error('ClubMail nicht verfügbar: ' + (data.error || 'ausgeloggt'));
}
const items = (data.items || []).filter(i => i.unread);
if (!items.length) return [];
return items.map(i => ({ json: i }));

const thread = $input.item.json;
const listItem = $('🔍 Nur ungelesene').item.json;

// Wenn schon ein Draft existiert → überspringen
if (thread.draft) {
  return [];
}

const messages = thread.messages || [];
if (!messages.length) return [];

// Nur die letzten 10 Nachrichten für Kontext
const recent = messages.slice(-10);
const history = recent.map(m => {
  const who = m.own ? 'Tobi (ich)' : listItem.name;
  return `${who}: ${m.text}`;
}).join('\n');

// Letzte eingehende Nachricht (nicht eigene)
const lastIncoming = [...messages].reverse().find(m => !m.own);
if (!lastIncoming) return [];

return [{ json: {
  name: listItem.name,
  lastMessage: lastIncoming.text,
  history,
  gender: listItem.gender || null
}}];

